parameters.text:
Review the full AI software factory execution context.

You must determine whether the generated application is ready for human validation and delivery.

Return ONLY valid JSON with this structure:

{
  "wf06_ai_review": {
    "quality_review": {
      "status": "passed | warning | failed",
      "findings": []
    },
    "security_review": {
      "status": "passed | warning | failed",
      "findings": []
    },
    "architecture_review": {
      "status": "passed | warning | failed",
      "findings": []
    },
    "test_review": {
      "status": "passed | warning | failed",
      "findings": []
    },
    "ci_cd_review": {
      "status": "passed | warning | failed",
      "findings": []
    },
    "blocking_issues": [],
    "recommendation": "approve | request_changes | block",
    "ready_for_delivery": true,
    "human_validation_required": true
  }
}

Each finding must be precise, actionable, and mapped to a specific part of the system.

Review context:
{{$json.review_context}}

parameters.jsCode:
const originalInput = $('Set - Prepare Review Context').item.json;
const current = $input.item.json;

let aiOutput =
  current.output ||
  current.text ||
  current.message ||
  current.content ||
  current.data ||
  current;

if (typeof aiOutput === 'string') {
  aiOutput = aiOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    aiOutput = JSON.parse(aiOutput);
  } catch (error) {
    aiOutput = {
      wf06_ai_review: {
        quality_review: {
          status: 'failed',
          findings: ['AI output could not be parsed as valid JSON.']
        },
        security_review: {
          status: 'warning',
          findings: []
        },
        architecture_review: {
          status: 'warning',
          findings: []
        },
        test_review: {
          status: 'warning',
          findings: []
        },
        ci_cd_review: {
          status: 'warning',
          findings: []
        },
        blocking_issues: ['Invalid JSON returned by AI reviewer.'],
        recommendation: 'block',
        ready_for_delivery: false,
        human_validation_required: true
      }
    };
  }
}

const review = aiOutput.wf06_ai_review || aiOutput;

const defaultSection = {
  status: 'warning',
  findings: []
};

return {
  json: {
    ...originalInput,
    wf06_ai_review: {
      quality_review: review.quality_review || defaultSection,
      security_review: review.security_review || defaultSection,
      architecture_review: review.architecture_review || defaultSection,
      test_review: review.test_review || defaultSection,
      ci_cd_review: review.ci_cd_review || defaultSection,
      blocking_issues: Array.isArray(review.blocking_issues) ? review.blocking_issues : [],
      recommendation: review.recommendation || 'request_changes',
      ready_for_delivery: Boolean(review.ready_for_delivery),
      human_validation_required: true
    }
  }
};

